# dijkstra.py
import heapq

def shortest_path(graph: dict[str, list[tuple[str, float]]], src: str, dst: str) -> tuple[float, list[str]]:
    """Compute the shortest path from src to dst in a weighted directed graph."""
    if src == dst:
        return (0.0, [src])
    distances = {node: float('inf') for node in graph}
    distances[src] = 0.0
    heap = [(0.0, src, [src])]
    while heap:
        current_dist, current_node, path = heapq.heappop(heap)
        if current_node == dst:
            return (current_dist, path)
        if current_dist > distances[current_node]:
            continue
        for neighbor, weight in graph[current_node]:
            new_dist = current_dist + weight
            if new_dist < distances[neighbor]:
                distances[neighbor] = new_dist
                new_path = path + [neighbor]
                heapq.heappush(heap, (new_dist, neighbor, new_path))
    return (float('inf'), [])
