# test_dijkstra.py
import pytest

from dijkstra import shortest_path

def test_shortest_path():
    graph = {
        'A': [('B', 1), ('C', 4)],
        'B': [('C', 2), ('D', 5)],
        'C': [('D', 1)],
        'D': []
    }
    distance, path = shortest_path(graph, 'A', 'D')
    assert distance == 4.0
    assert path == ['A', 'B', 'C', 'D']

def test_same_node():
    graph = {'A': []}
    distance, path = shortest_path(graph, 'A', 'A')
    assert distance == 0.0
    assert path == ['A']

def test_no_path():
    graph = {'A': [('B', 1)], 'B': []}
    distance, path = shortest_path(graph, 'A', 'C')
    assert distance == float('inf')
    assert path == []

def test_property_path_validity():
    graph = {
        'X': [('Y', 3), ('Z', 2)],
        'Y': [('Z', 1)],
        'Z': []
    }
    distance, path = shortest_path(graph, 'X', 'Z')
    assert distance == 2.0
    assert path == ['X', 'Z']

    # Check that the sum of the weights in the path equals the distance
    total = 0.0
    for i in range(len(path) - 1):
        current = path[i]
        next_node = path[i + 1]
        found = False
        for neighbor, weight in graph[current]:
            if neighbor == next_node:
                total += weight
                found = True
                break
        if not found:
            pytest.fail(f"Edge {current} -> {next_node} not found in the graph")
    assert total == distance
